document.addEventListener("nav",()=>{let t=document.querySelector(".board");if(!t)return;let r=t.querySelector(".board-filter");if(!r)return;let a=Array.from(t.querySelectorAll(".board-card")),d=Array.from(t.querySelectorAll(".board-column")),o=()=>{let c=r.value;for(let e of a){let n=e.getAttribute("data-project")??"";e.hidden=c!=="__all__"&&n!==c}for(let e of d){let n=e.querySelectorAll(".board-card:not([hidden])").length,l=e.querySelector(".board-count");l&&(l.textContent=String(n))}};r.addEventListener("change",o),o(),window.addCleanup(()=>r.removeEventListener("change",o))});
